import{_ as t,o as a,c as o,ae as n}from"./chunks/framework.BMBGeRFM.js";const u=JSON.parse('{"title":"Writing a news post","description":"","frontmatter":{},"headers":[],"relativePath":"news/_read.md","filePath":"news/_read.md"}'),i={name:"news/_read.md"};function d(s,e,r,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="writing-a-news-post" tabindex="-1">Writing a news post <a class="header-anchor" href="#writing-a-news-post" aria-label="Permalink to &quot;Writing a news post&quot;">​</a></h1><ol><li>Copy <code>_template.md</code> to <code>YYYY-MM-DD-some-slug.md</code> in this folder.</li><li>Edit the frontmatter <code>title</code> and <code>date</code>. Write your post body below.</li><li>Commit and push. The post appears at <code>/news/YYYY-MM-DD-some-slug</code> and on the <code>/news/</code> index automatically.</li></ol><h2 id="naming-convention" tabindex="-1">Naming convention <a class="header-anchor" href="#naming-convention" aria-label="Permalink to &quot;Naming convention&quot;">​</a></h2><p><code>YYYY-MM-DD-slug.md</code> — the date prefix keeps the folder sortable and makes URLs self-documenting. The slug should be hyphenated lowercase words, e.g. <code>2026-04-18-bleed-persistence-fix.md</code>.</p><h2 id="what-goes-in-here" tabindex="-1">What goes in here? <a class="header-anchor" href="#what-goes-in-here" aria-label="Permalink to &quot;What goes in here?&quot;">​</a></h2><p>Anything that doesn&#39;t fit in the changelog. Release announcements with context, design rationale (&quot;why we did X&quot;), tutorials, roadmap updates, &quot;farben at $thing&quot; event posts, retrospectives. The changelog answers &quot;what changed&quot;; news answers &quot;why and how it felt to change it.&quot;</p><h2 id="excluding-a-draft" tabindex="-1">Excluding a draft <a class="header-anchor" href="#excluding-a-draft" aria-label="Permalink to &quot;Excluding a draft&quot;">​</a></h2><p>Prefix the filename with <code>_</code> (e.g. <code>_draft-thing.md</code>) and the data loader will skip it. Same trick the template file uses.</p>',8)])])}const m=t(i,[["render",d]]);export{u as __pageData,m as default};
